import psycopg2
import sys

def install_extension(host, dbname, user, password, extension_name):
    conn = None
    try:
        conn = psycopg2.connect(host=host, database=dbname, user=user, password=password)
        conn.autocommit = True
        cur = conn.cursor()

        print(f"Attempting to create extension: {extension_name}")
        cur.execute(f"CREATE EXTENSION IF NOT EXISTS {extension_name}")
        print(f"Extension '{extension_name}' created successfully.")

        cur.close()

    except psycopg2.Error as e:
        print(f"Error installing extension '{extension_name}': {e}")
        print("Please ensure you have sufficient permissions (e.g., superuser) and the extension is available on the server.")
        sys.exit(1)
    finally:
        if conn:
            conn.close()

if __name__ == "__main__":
    print("PostgreSQL Extension Installer")
